/* ═══════════════════════════════════════════════════════════════════════
   AfriFlow AI — Course-specific lesson data
   Each course has 8 tailored lessons with real content
   ═══════════════════════════════════════════════════════════════════════ */

export interface LessonData {
  id: string
  title: string
  duration: string
  content: string
  isFree: boolean
  completed: boolean
}

type LessonTemplate = { title: string; duration: string; content: string; isFree: boolean }

function buildLessons(templates: LessonTemplate[]): LessonData[] {
  return templates.map((t, i) => ({ ...t, id: String(i + 1), completed: false }))
}

