/*  Build and export the final lesson map                                 */
/* ═══════════════════════════════════════════════════════════════════════ */

import { SAMPLE_COURSES } from '@/lib/data'

export function getLessonsForCourse(slug: string): LessonData[] {
  const template = COURSE_LESSONS[slug]
  if (template) return buildLessons(template)

  // fallback: generate contextual lessons for courses without custom lessons
  const course = SAMPLE_COURSES.find(c => c.slug === slug)
  if (!course) return []
  return buildLessons(generateGenericLessons(course))
}
